content:
{
  "sentences": [
    {
      "text": "從車站到醫院怎麼去？",
      "pinyin": "Cóng chēzhàn dào yīyuàn zěnme qù?",
      "pinyin_numeric": "cong2 che1zhan4 dao4 yi1yuan4 zen3me5 qu4",
      "translation_en": "How do I get from the station to the hospital?",
      "translation_ko": "역에서 병원까지 어떻게 가나요?"
    },
    {
      "text": "從這裡到台北車站可以搭捷運嗎？",
      "pinyin": "Cóng zhèlǐ dào Táiběi chēzhàn kěyǐ dā jiéyùn ma?",
      "pinyin_numeric": "cong2 zhe4li3 dao4 Tai2bei3 che1zhan4 ke3yi3 da1 jie2yun4 ma0",
      "translation_en": "Can I take the MRT from here to Taipei Station?",
      "translation_ko": "여기에서 타이베이 역까지 지하철을 탈 수 있나요?"
    },
    {
      "text": "從我家到公司搭公車大概要三十分鐘。",
      "pinyin": "Cóng wǒ jiā dào gōngsī dā gōngchē dàgài yào sānshí fēnzhōng.",
      "pinyin_numeric": "cong2 wo3 jia1 dao4 gong1si1 da1 gong1che1 da4gai4 yao4 san1shi2 fen1zhong1",
      "translation_en": "It takes about thirty minutes by bus from my home to the company.",
      "translation_ko": "우리 집에서 회사까지 버스로 약 30분 걸려요."
    },
    {
      "text": "從捷運站到學校走路比較慢，可以騎腳踏車。",
      "pinyin": "Cóng jiéyùn zhàn dào xuéxiào zǒulù bǐjiào màn, kěyǐ qí jiǎotàchē.",
      "pinyin_numeric": "cong2 jie2yun4 zhan4 dao4 xue2xiao4 zou3lu4 bi3jiao4 man4, ke3yi3 qi2 jiao3ta4che1",
      "translation_en": "Walking from the MRT station to school is slower; you can ride a bike.",
      "translation_ko": "지하철역에서 학교까지 걷는 것은 비교적 느리니 자전거를 탈 수 있어요."
    },
    {
      "text": "從圖書館到公園怎麼去？搭公車還是走路？",
      "pinyin": "Cóng túshūguǎn dào gōngyuán zěnme qù? Dā gōngchē háishì zǒulù?",
      "pinyin_numeric": "cong2 tu2shu1guan3 dao4 gong1yuan2 zen3me5 qu4? da1 gong1che1 hai2shi4 zou3lu4?",
      "translation_en": "How do I get from the library to the park? By bus or on foot?",
      "translation_ko": "도서관에서 공원까지 어떻게 가나요? 버스를 타거나 걸어서요?"
    },
    {
      "text": "從這裡到夜市叫計程車比較快，可是比較貴。",
      "pinyin": "Cóng zhèlǐ dào yèshì jiào jìchéngchē bǐjiào kuài, kěshì bǐjiào guì.",
      "pinyin_numeric": "cong2 zhe4li3 dao4 ye4shi4 jiao4 ji4cheng2che1 bi3jiao4 kuai4, ke3shi4 bi3jiao4 gui4",
      "translation_en": "Taking a taxi from here to the night market is faster, but more expensive.",
      "translation_ko": "여기에서 야시장까지 택시를 부르는 것이 더 빠르지만 더 비싸요."
    },
    {
      "text": "從學校到車站要轉車嗎？",
      "pinyin": "Cóng xuéxiào dào chēzhàn yào zhuǎn chē ma?",
      "pinyin_numeric": "cong2 xue2xiao4 dao4 che1zhan4 yao4 zhuan3 che1 ma0",
      "translation_en": "Do I need to transfer from school to the station?",
      "translation_ko": "학교에서 역까지 환승해야 하나요?"
    },
    {
      "text": "從我家到公司搭公車要轉車，可是搭捷運不用。",
      "pinyin": "Cóng wǒ jiā dào gōngsī dā gōngchē yào zhuǎn chē, kěshì dā jiéyùn bùyòng.",
      "pinyin_numeric": "cong2 wo3 jia1 dao4 gong1si1 da1 gong1che1 yao4 zhuan3 che1, ke3shi4 da1 jie2yun4 bu4yong4",
      "translation_en": "From my home to the company, I need to transfer by bus, but not by MRT.",
      "translation_ko": "우리 집에서 회사까지 버스는 환승해야 하지만 지하철은 환승할 필요가 없어요."
    },
    {
      "text": "從捷運站到公園走路大概十分鐘，不用搭公車。",
      "pinyin": "Cóng jiéyùn zhàn dào gōngyuán zǒulù dàgài shí fēnzhōng, bùyòng dā gōngchē.",
      "pinyin_numeric": "cong2 jie2yun4 zhan4 dao4 gong1yuan2 zou3lu4 da4gai4 shi2 fen1zhong1, bu4yong4 da1 gong1che1",
      "translation_en": "It's about a ten-minute walk from the MRT station to the park; no need to take the bus.",
      "translation_ko": "지하철역에서 공원까지 걸어서 약 10분이니 버스를 탈 필요가 없어요."
    },
    {
      "text": "從這裡到目的地搭計程車要多少錢？",
      "pinyin": "Cóng zhèlǐ dào mùdìdì dā jìchéngchē yào duōshao qián?",
      "pinyin_numeric": "cong2 zhe4li3 dao4 mu4di4di4 da1 ji4cheng2che1 yao4 duo1shao3 qian2?",
      "translation_en": "How much does it cost to take a taxi from here to the destination?",
      "translation_ko": "여기에서 목적지까지 택시를 타면 얼마인가요?"
    }
  ]
}
